1	//! Layer 1 External API Gateway.
2	//!
3	//! How external AI agents connect to the Agent Nervous System.
4	//! Three protocols, one gateway:
5	//!
6	//! - **MCP server** (Model Context Protocol): JSON-RPC tool provider
7	//!   for Claude, `ChatGPT`, and other MCP-compatible agents.
8	//! - **REST API**: Simple HTTP endpoints for non-MCP agents.
9	//! - **WebSocket**: Streaming events for real-time agent feedback.
10	//!
11	//! All connections are authenticated (API key), rate-limited, and
12	//! budget-tracked before any internal gRPC call is made.
13	
14	pub mod auth;
15	pub mod client;
16	pub mod mcp;
17	pub mod metrics;
18	pub mod rest;
19	pub mod ws;
20	
21	use std::net::SocketAddr;
22	use axum::routing::{get, post};
23	use axum::Router;
24	
25	use std::sync::Arc;
26	
27	use auth::SharedKeyRegistry;
28	use client::InternalClient;
29	use mcp::McpServer;
30	use metrics::Metrics;
31	use rest::ApiRouter;
32	use ws::WebSocketServer;
33	
34	/// Shared gateway state, created once at startup.
35	#[derive(Clone)]
36	pub struct Gateway {
37	    key_registry: SharedKeyRegistry,
38	    pub metrics: Arc<Metrics>,
39	    mcp: McpServer,
40	    rest: ApiRouter,
41	    ws: WebSocketServer,
42	}
43	
44	impl Gateway {
45	    /// Initialize the gateway: load API keys, connect to the daemon.
46	    pub async fn init(grpc_port: u16) -> Result<Self, Box<dyn std::error::Error>> {
47	        let key_registry = Arc::new(auth::KeyRegistry::load(None)?);
48	        let internal = InternalClient::connect(grpc_port).await?;
49	        let metrics = Arc::new(Metrics::new());
50	        let mcp = McpServer::new(internal.clone());
51	        let rest = ApiRouter::new(internal.clone());
52	        let ws = WebSocketServer::new(internal);
53	
54	        Ok(Self {
55	            key_registry,
56	            metrics,
57	            mcp,
58	            rest,
59	            ws,
60	        })
61	    }
62	
63	    /// Build the axum router.
64	    ///
65	    /// **One flat Router** — no `nest()`, no `merge()`.
66	    /// axum 0.7 `nest()` drops `{param}` captures and `merge()` with
67	    /// `route_layer` silently discards parameterized routes.
68	    /// A single flat Router with path-aware auth is the only reliable pattern.
69	    pub fn router(&self) -> Router {
70	        let rest = self.rest.clone();
71	        let mcp = self.mcp.clone();
72	        let ws = self.ws.clone();
73	        let registry = Arc::clone(&self.key_registry);
74	        let metrics_arc = Arc::clone(&self.metrics);
75	
76	        // Path-aware auth middleware: skips public routes, enforces API key on
77	        // everything else.
78	        let auth_mw = axum::middleware::from_fn({
79	            let registry = Arc::clone(&registry);
80	            move |request: axum::extract::Request, next: axum::middleware::Next| {
81	                let registry = Arc::clone(&registry);
82	                async move {
83	                    let path = request.uri().path().to_owned();
84	
85	                    // Public routes — no API key required.
86	                    if path == "/api/v1/health"
87	                        || path == "/api/v1/metrics"
88	                        || path == "/mcp"
89	                        || path == "/ws"
90	                    {
91	                        return next.run(request).await;
92	                    }
93	
94	                    let api_key = auth::extract_api_key(request.headers(), None);
95	                    let valid = api_key
96	                        .as_ref()
97	                        .and_then(|k| registry.validate(k))
98	                        .is_some();
99	                    if valid {
100	                        next.run(request).await
101	                    } else {
102	                        let body = if api_key.is_some() {
103	                            r#"{"error":"invalid API key"}"#
104	                        } else {
105	                            r#"{"error":"missing X-API-Key header"}"#
106	                        };
107	                        axum::response::Response::builder()
108	                            .status(axum::http::StatusCode::UNAUTHORIZED)
109	                            .body(axum::body::Body::from(body))
110	                            .expect("building a 401 response is infallible")
111	                    }
112	                }
113	            }
114	        });
115	
116	        // Single flat Router — every route registered directly.
117	        // No nest(), no merge() — both break {param} captures in axum 0.7.
118	        Router::new()
119	            // ── Public routes ──────────────────────────────────────
120	            .route(
121	                "/mcp",
122	                post(
123	                    move |body: axum::extract::Json<serde_json::Value>| async move {
124	                        let response = mcp.handle_request(body.0).await;
125	                        axum::Json(response)
126	                    },
127	                ),
128	            )
129	            .route(
130	                "/ws",
131	                get(
132	                    move |ws_upgrade: axum::extract::ws::WebSocketUpgrade| async move {
133	                        ws.handle_upgrade(ws_upgrade).await
134	                    },
135	                ),
136	            )
137	            .route(
138	                "/api/v1/health",
139	                get({
140	                    let rest = rest.clone();
141	                    move || {
142	                        let rest = rest.clone();
143	                        async move { rest.health().await }
144	                    }
145	                }),
146	            )
147	            .route(
148	                "/api/v1/metrics",
149	                get(move || {
150	                    let m = Arc::clone(&metrics_arc);
151	                    async move { m.render() }
152	                }),
153	            )
154	            // ── Session routes ─────────────────────────────────────
155	            .route(
156	                "/api/v1/sessions",
157	                post({
158	                    let rest = rest.clone();
159	                    move |axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
160	                        rest.create_session(body).await
161	                    }
162	                }),
163	            )
164	            .route(
165	                "/api/v1/sessions/{id}/navigate",
166	                post({
167	                    let rest = rest.clone();
168	                    move |axum::extract::Path(id): axum::extract::Path<String>,
169	                          axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
170	                        rest.navigate(&id, body).await
171	                    }
172	                }),
173	            )
174	            .route(
175	                "/api/v1/sessions/{id}/execute",
176	                post({
177	                    let rest = rest.clone();
178	                    move |axum::extract::Path(id): axum::extract::Path<String>,
179	                          axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
180	                        rest.execute_action(&id, body).await
181	                    }
182	                }),
183	            )
184	            .route(
185	                "/api/v1/sessions/{id}/screenshot",
186	                post({
187	                    let rest = rest.clone();
188	                    move |axum::extract::Path(id): axum::extract::Path<String>,
189	                          axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
190	                        rest.screenshot(&id, body).await
191	                    }
192	                }),
193	            )
194	            .route(
195	                "/api/v1/sessions/{id}/dom",
196	                get({
197	                    let rest = rest.clone();
198	                    move |axum::extract::Path(id): axum::extract::Path<String>| async move {
199	                        rest.get_dom(&id).await
200	                    }
201	                }),
202	            )
203	            // ── Goal routes ────────────────────────────────────────
204	            .route(
205	                "/api/v1/goals",
206	                post({
207	                    let rest = rest.clone();
208	                    move |axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
209	                        rest.create_goal(body).await
210	                    }
211	                }),
212	            )
213	            .route(
214	                "/api/v1/goals/{id}",
215	                get({
216	                    let rest = rest.clone();
217	                    move |axum::extract::Path(id): axum::extract::Path<String>| async move {
218	                        rest.get_goal(&id).await
219	                    }
220	                }),
221	            )
222	            // Auth middleware applies to everything, but skips public paths.
223	            .route_layer(auth_mw)
224	    }
225	
226	    /// Start the gateway HTTP server on the given address.
227	    /// Blocks until the server exits.
228	    pub async fn serve(self, addr: SocketAddr) -> Result<(), Box<dyn std::error::Error>> {
229	        let router = self.router();
230	
231	        tracing::info!("Gateway starting on {}", addr);
232	
233	        let listener = tokio::net::TcpListener::bind(addr).await?;
234	        axum::serve(listener, router).await?;
235	
236	        Ok(())
237	    }
238	}
