604	
605	    async fn classify_distractions(
606	        &self,
607	        request: Request<DistractionRequest>,
608	    ) -> Result<Response<DistractionList>, Status> {
609	        let req = request.into_inner();
610	        let url = req.url;
611	
612	        // Extract CSS class/id hints from DOM elements for distraction pattern matching
613	        let css_hints = req
614	            .dom
615	            .as_ref()
616	            .map(|dom| {
617	                dom.elements
618	                    .iter()
619	                    .flat_map(|el| {
620	                        el.attributes
621	                            .iter()
622	                            .filter(|(k, _)| *k == "class" || *k == "id")
623	                            .map(|(_, v)| v.clone())
624	                    })
625	                    .collect::<Vec<_>>()
626	                    .join(" ")
627	            })
628	            .unwrap_or_default();
629	
630	        // Extract all visible text from the distilled DOM for content scanning
631	        let dom_text = req
632	            .dom
633	            .as_ref()
634	            .map(|dom| {
635	                dom.elements
636	                    .iter()
637	                    .map(|el| el.text.as_str())
638	                    .collect::<Vec<_>>()
639	                    .join(" ")
640	            })
641	            .unwrap_or_default();
642	
643	        self.metrics.inc_immune_scans();
644	        let classifier = ans_immune::DistractionClassifier;
645	        let flags = classifier.classify(&url, &dom_text, &css_hints);
646	
647	        let distractions: Vec<_> = flags
648	            .iter()
649	            .map(ans_immune::serialization::distraction_to_proto_list_item)
650	            .collect();
651	
652	        Ok(Response::new(DistractionList {
653	            distractions,
654	            classification_time_us: 0,
655	        }))
656	    }
