1	//! Goal lifecycle manager.
2	//!
3	//! Creates goals, decomposes them into sub-goals with a basic heuristic
4	//! (Python coordinator over gRPC is Phase 4), tracks progress in the
5	//! shared [`GoalStateStore`].
6	
7	use std::collections::HashMap;
8	
9	use ans_core::goal::{GoalContext, GoalState, GoalStatus, SubGoal, SubGoalStatus};
10	use uuid::Uuid;
11	
12	use crate::store::{GoalStateStore, GoalStoreError};
13	
14	/// Manages the lifecycle of all active goals.
15	///
16	/// Cloning shares the underlying store (Arc pointer copy).
17	#[derive(Clone)]
18	pub struct GoalManager {
19	    store: GoalStateStore,
20	}
21	
22	impl GoalManager {
23	    /// Create a new, empty goal manager.
24	    #[must_use] 
25	    pub fn new() -> Self {
26	        Self {
27	            store: GoalStateStore::new(256),
28	        }
29	    }
30	
31	    /// Create a goal and decompose into sub-goals.
32	    ///
33	    /// Decomposition uses a keyword-based heuristic. Full LLM decomposition
34	    /// via the Python coordinator is deferred to Phase 4.
35	    pub fn create_goal(
36	        &self,
37	        description: &str,
38	        context: &HashMap<String, String>,
39	        _max_steps: u32,
40	    ) -> Result<GoalState, GoalStoreError> {
41	        let goal_id = Uuid::new_v4();
42	        let sub_goals = decompose_heuristic(description);
43	        let url = context.get("current_url").cloned();
44	
45	        let total = sub_goals.len() as f32;
46	        let done = sub_goals
47	            .iter()
48	            .filter(|s| s.status == SubGoalStatus::Done)
49	            .count() as f32;
50	        let progress = if total > 0.0 { done / total } else { 0.0 };
51	
52	        let status = if progress >= 1.0 {
53	            GoalStatus::Completed
54	        } else {
55	            GoalStatus::Active
56	        };
57	
58	        let state = GoalState {
59	            goal_id,
60	            description: description.to_string(),
61	            status,
62	            progress,
63	            sub_goals,
64	            context: GoalContext {
65	                current_url: url,
66	                last_action: None,
67	                last_observation: None,
68	                intent_embedding: vec![],
69	                distraction_count: 0,
70	            },
71	            created_at: chrono::Utc::now(),
72	            updated_at: chrono::Utc::now(),
73	        };
74	
75	        self.store.insert(state.clone())?;
76	        Ok(state)
77	    }
78	
79	    /// Retrieve a goal state by ID.
80	    #[must_use] 
81	    pub fn get_goal_state(&self, goal_id: &Uuid) -> Option<GoalState> {
82	        self.store.get(goal_id)
83	    }
84	
85	    /// Update progress and status for an existing goal.
86	    pub fn update_progress(
87	        &self,
88	        goal_id: Uuid,
89	        progress: f32,
90	        status: GoalStatus,
91	    ) -> Result<GoalState, GoalStoreError> {
92	        self.store.update_progress(goal_id, progress, status)
93	    }
94	
95	    /// Replace sub-goals from Python LLM decomposer.
96	    pub fn update_sub_goals(
97	        &self,
98	        goal_id: Uuid,
99	        sub_goals: Vec<SubGoal>,
100	    ) -> Result<GoalState, GoalStoreError> {
101	        self.store.update_sub_goals(goal_id, sub_goals)
102	    }
103	
104	    /// List all active goal IDs.
105	    #[must_use] 
106	    pub fn list_ids(&self) -> Vec<Uuid> {
107	        self.store.list_ids()
108	    }
109	
110	    /// Number of active goals.
111	    #[allow(dead_code)]
112	    #[must_use] 
113	    pub fn active_count(&self) -> usize {
114	        self.store.len()
115	    }
116	
117	    /// Underlying store reference — for subscribers.
118	    #[must_use] 
119	    pub const fn store(&self) -> &GoalStateStore {
120	        &self.store
121	    }
122	
123	    /// Subscribe to goal state change notifications.
124	    #[must_use] 
125	    pub fn subscribe(
126	        &self,
127	    ) -> tokio::sync::broadcast::Receiver<crate::store::GoalStateNotification> {
128	        self.store.subscribe()
129	    }
130	}
131	
132	impl Default for GoalManager {
133	    fn default() -> Self {
134	        Self::new()
135	    }
136	}
137	
138	// ── Heuristic decomposition ──────────────────────────────────────────
139	
140	/// Action verbs mapped to their typical pre-requisites and verification steps.
141	const NAVIGATION_VERBS: &[&str] = &[
142	    "go to", "navigate", "visit", "open", "browse", "find", "search",
143	];
144	
145	const INPUT_VERBS: &[&str] = &[
146	    "fill", "type", "enter", "input", "write", "set", "select", "choose", "pick", "check", "click",
147	    "submit",
148	];
149	
150	const EXTRACTION_VERBS: &[&str] = &[
151	    "read", "extract", "get", "fetch", "download", "scrape", "collect", "copy", "export", "save",
152	];
153	
154	fn decompose_heuristic(description: &str) -> Vec<SubGoal> {
155	    let lower = description.to_lowercase();
156	    let has_navigation = NAVIGATION_VERBS.iter().any(|v| lower.contains(v));
157	    let has_input = INPUT_VERBS.iter().any(|v| lower.contains(v));
158	    let has_extraction = EXTRACTION_VERBS.iter().any(|v| lower.contains(v));
159	
160	    let mut sub_goals = Vec::with_capacity(3);
161	    #[allow(clippy::useless_let_if_seq)]
162	    let mut prev_id: Option<Uuid> = None;
163	
164	    // 1. Navigation phase
165	    if has_navigation {
166	        let id = Uuid::new_v4();
167	        sub_goals.push(SubGoal {
168	            id,
169	            description: format!("Navigate to the target page for: {description}"),
170	            success_criteria: vec!["Page loaded successfully".into()],
171	            depends_on: vec![],
172	            status: SubGoalStatus::Active,
173	        });
174	        prev_id = Some(id);
175	    }
176	
177	    // 2. Interaction phase
178	    if has_input {
179	        let id = Uuid::new_v4();
180	        let deps: Vec<Uuid> = prev_id.into_iter().collect();
181	        sub_goals.push(SubGoal {
182	            id,
183	            description: format!("Interact with the page to complete: {description}"),
184	            success_criteria: vec!["All required fields populated".into()],
185	            depends_on: deps,
186	            status: SubGoalStatus::Pending,
187	        });
188	        prev_id = Some(id);
189	    }
190	
191	    // 3. Verification / extraction phase
192	    if has_extraction || !sub_goals.is_empty() {
193	        let id = Uuid::new_v4();
194	        let deps: Vec<Uuid> = prev_id.into_iter().collect();
195	        sub_goals.push(SubGoal {
196	            id,
197	            description: format!("Verify result for: {description}"),
198	            success_criteria: vec!["Expected outcome confirmed".into()],
199	            depends_on: deps,
200	            status: SubGoalStatus::Pending,
201	        });
202	    }
203	
204	    // Fallback — single sub-goal for unrecognized descriptions
205	    if sub_goals.is_empty() {
206	        sub_goals.push(SubGoal {
207	            id: Uuid::new_v4(),
208	            description: format!("Complete: {description}"),
209	            success_criteria: vec!["Task completed successfully".into()],
210	            depends_on: vec![],
211	            status: SubGoalStatus::Active,
212	        });
213	    }
214	
215	    sub_goals
216	}
