209	impl ans_core::BrowserBackend for CdpBackend {
210	    async fn navigate(&self, url: &str, timeout: Duration) -> Result<PageState, BrowserError> {
211	        tracing::info!(%url, "Navigating");
212	
213	        let cmd = command::page_navigate(url);
214	        let result = self.connection.send_command(cmd, timeout).await?;
215	        let _nav = command::parse_navigation_result(&result);
216	
217	        // Wait briefly for the page to start loading, then get frame tree
218	        tokio::time::sleep(Duration::from_millis(500)).await;
219	
220	        let frame_tree = self
221	            .connection
222	            .send_command(command::page_get_frame_tree(), timeout)
223	            .await?;
224	        let tree = command::parse_frame_tree(&frame_tree);
225	        let info = command::parse_page_info(&tree);
226	
227	        // Try to get title via JS
228	        let title = self
229	            .connection
230	            .send_command(
231	                command::runtime_evaluate("document.title"),
232	                Duration::from_secs(5),
233	            )
234	            .await
235	            .ok()
236	            .and_then(|v| v.as_str().map(String::from))
237	            .unwrap_or_else(|| info.title.clone());
238	
239	        let dom_nodes = self
240	            .connection
241	            .send_command(
242	                command::runtime_evaluate("document.querySelectorAll('*').length"),
243	                Duration::from_secs(5),
244	            )
245	            .await
246	            .ok()
247	            .and_then(|v| v.as_u64())
248	            .unwrap_or(0);
249	
250	        let visible_text = self
251	            .connection
252	            .send_command(
253	                command::runtime_evaluate("document.body?.innerText?.slice(0, 2000) || ''"),
254	                Duration::from_secs(5),
255	            )
256	            .await
257	            .ok()
258	            .and_then(|v| {
259	                v.as_str().map(|s| {
260	                    s.lines()
261	                        .filter(|l| !l.trim().is_empty())
262	                        .map(String::from)
263	                        .take(50)
264	                        .collect::<Vec<_>>()
265	                })
266	            })
267	            .unwrap_or_default();
268	
269	        *self.current_url.lock().await = info.url.clone();
270	
271	        Ok(PageState {
272	            url: info.url,
273	            title,
274	            loaded: info.loaded,
275	            dom_node_count: dom_nodes,
276	            visible_text,
277	            timestamp: chrono::Utc::now(),
278	        })
279	    }
