```rust
use std::collections::HashSet;
use serde_json::json;

/// WebSocket server state.
#[derive(Clone)]
pub struct WebSocketServer {
    pub client: InternalClient,
    /// Local event bus for forwarding to WS clients.
    event_tx: broadcast::Sender<String>,
}

impl WebSocketServer {
    pub fn new(client: InternalClient, event_tx: broadcast::Sender<String>) -> Self {
        Self { client, event_tx }
    }

    pub fn event_sender(&self) -> broadcast::Sender<String> {
        self.event_tx.clone()
    }

    pub fn push_event(&self, event: &str) {
        let _ = self.event_tx.send(event.to_string());
    }

    pub async fn handle_upgrade(&self, ws: WebSocketUpgrade) -> impl IntoResponse {
        let event_rx = self.event_tx.subscribe();
        ws.on_upgrade(move |socket| handle_socket(socket, event_rx))
    }
}

async fn handle_socket(socket: WebSocket, rx: broadcast::Receiver<String>) {
    let (mut sender, mut receiver) = socket.split();

    // Welcome message
    let welcome = json!({
        "type": "connected",
        "message": "Connected to Agent Nervous System gateway",
        "version": env!("CARGO_PKG_VERSION")
    });
    let _ = sender.send(Message::Text(welcome.to_string())).await;

    // Per-connection goal filter set
    let subscribed_goals: std::sync::Arc<tokio::sync::Mutex<HashSet<String>>> =
        std::sync::Arc::new(tokio::sync::Mutex::new(HashSet::new()));

    // Spawn event forwarding from broadcast -> WebSocket
    let mut event_rx = rx;
    let send_goals = subscribed_goals.clone();
    let send_handle = tokio::spawn(async move {
        while let Ok(event) = event_rx.recv().await {
            // Parse event to extract goal_id for filtering
            let should_send = if let Ok(parsed) = serde_json::from_str::<serde_json::Value>(&event) {
                let goal_filter = send_goals.lock().await;
                if goal_filter.is_empty() {
                    true // No filter — send everything
                } else {
                    parsed.get("goal_id")
                        .and_then(|v| v.as_str())
                        .map(|gid| goal_filter.contains(gid))
                        .unwrap_or(false)
                }
            } else {
                true
            };

            if should_send {
                if sender.send(Message::Text(event)).await.is_err() {
                    break;
                }
            }
        }
    });

    // Process incoming messages
    while let Some(Ok(msg)) = receiver.next().await {
        match msg {
            Message::Text(text) => {
                // Handle subscription: {"goal_id": "..."}
                if let Ok(cmd) = serde_json::from_str::<serde_json::Value>(&text) {
                    if let Some(goal_id) = cmd.get("goal_id").and_then(|v| v.as_str()) {
                        let mut goals = subscribed_goals.lock().await;
                        goals.insert(goal_id.to_string());
                        let ack = json!({
                            "type": "subscribed",
                            "goal_id": goal_id,
                        });
                        let _ = sender.send(Message::Text(ack.to_string())).await;
                    }
                    if let Some(goal_id) = cmd.get("unsubscribe").and_then(|v| v.as_str()) {
                        let mut goals = subscribed_goals.lock().await;
                        goals.remove(goal_id);
                    }
                }
            }
            Message::Ping(_) => {}
            Message::Close(_) => break,
            _ => {}
        }
    }

    send_handle.abort();
}
