<script>
const WS_URL = `ws://${location.host}/ws`;
const API_URL = '';

let ws = null;
let goals = {}; // goal_id -> goal state
let wsConnected = false;

function connectWS() {
  ws = new WebSocket(WS_URL);
  ws.onopen = () => {
    wsConnected = true;
    document.getElementById('wsDot').className = 'status-dot connected';
    document.getElementById('wsStatus').textContent = 'Connected';
  };
  ws.onclose = () => {
    wsConnected = false;
    document.getElementById('wsDot').className = 'status-dot disconnected';
    document.getElementById('wsStatus').textContent = 'Disconnected — reconnecting...';
    setTimeout(connectWS, 2000);
  };
  ws.onerror = () => {
    wsConnected = false;
  };
  ws.onmessage = (event) => {
    try {
      const data = JSON.parse(event.data);
      handleWSEvent(data);
    } catch (e) {
      console.warn('Invalid WS message:', event.data);
    }
  };
}

function handleWSEvent(data) {
  const type = data.type;
  if (type === 'connected') {
    console.log('WS connected:', data.message);
    return;
  }
  if (type === 'goal_created') {
    goals[data.goal_id] = {
      description: data.description,
      progress: data.progress || 0,
      status: data.status || 'active',
      sub_goals: data.sub_goals || [],
      created_at: Date.now()
    };
    renderGoals();
    showToast(`Goal created: ${data.description.slice(0, 60)}`, 'success');
  }
  if (type === 'goal_update') {
    if (goals[data.goal_id]) {
      goals[data.goal_id].progress = data.progress;
      goals[data.goal_id].status = data.status;
      if (data.sub_goals) {
        goals[data.goal_id].sub_goals = data.sub_goals;
      }
    } else {
      goals[data.goal_id] = {
        description: data.description || 'Goal ' + data.goal_id.slice(0, 8),
        progress: data.progress || 0,
        status: data.status || 'active',
        sub_goals: data.sub_goals || [],
        created_at: Date.now()
      };
    }
    renderGoals();
    // Update eye statuses based on metadata if available
    if (data.eye_updates) {
      updateEyes(data.eye_updates);
    }
  }
}

function updateEyes(eyeUpdates) {
  for (const [eyeName, status] of Object.entries(eyeUpdates)) {
    const el = document.getElementById('eye-' + eyeName.replace('_', '-'));
    if (el) {
      el.className = 'glass eye-tile ' + (status === 'active' ? 'active' : 'idle');
      el.querySelector('.eye-status').textContent = status;
    }
  }
}

async function submitGoal() {
  const input = document.getElementById('goalInput');
  const goal = input.value.trim();
  if (!goal) return;

  const btn = document.getElementById('submitBtn');
  btn.disabled = true;
  btn.textContent = 'Creating...';

  try {
    const resp = await fetch('/api/v1/goals', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ description: goal, max_steps: 100 })
    });
    const data = await resp.json();
    if (data.error) {
      showToast('Error: ' + data.error, 'error');
    } else {
      input.value = '';
      input.focus();
    }
  } catch (e) {
    showToast('Failed to create goal: ' + e.message, 'error');
  } finally {
    btn.disabled = false;
    btn.textContent = 'Run Goal';
  }
}

function renderGoals() {
  const grid = document.getElementById('goalsGrid');
  const entries = Object.entries(goals).sort((a, b) => b[1].created_at - a[1].created_at);

  if (entries.length === 0) {
    grid.innerHTML = `<div class="glass empty-state">
      <div class="empty-icon">&#x1F3AF;</div>
      <p>No active goals. Submit a goal above to get started.</p>
    </div>`;
    document.getElementById('activeCount').textContent = '0';
    return;
  }

  document.getElementById('activeCount').textContent =
    entries.filter(([_, g]) => g.status === 'active' || g.status === 'pending').length;

  grid.innerHTML = entries.map(([id, goal]) => {
    const pct = Math.round((goal.progress || 0) * 100);
    const statusClass = goal.status === 'completed' ? 'completed'
      : goal.status === 'failed' ? 'failed' : '';

    let subGoalsHTML = '';
    if (goal.sub_goals && goal.sub_goals.length > 0) {
      subGoalsHTML = '<div class="sub-goals">' +
        goal.sub_goals.map(sg => {
          const dotClass = sg.status === 'Done' || sg.status === 'done' ? 'done'
            : sg.status === 'Active' || sg.status === 'active' ? 'active'
            : sg.status === 'Blocked' || sg.status === 'blocked' ? 'blocked'
            : 'pending';
          return `<div class="sub-goal-item">
            <span class="sub-goal-dot ${dotClass}"></span>
            ${escapeHtml(sg.description)}
          </div>`;
        }).join('') + '</div>';
    }

    return `<div class="glass goal-card ${statusClass}">
      <div class="goal-title">${escapeHtml(goal.description)}</div>
      <div class="goal-meta">
        <span>${pct}% complete</span>
        <span style="text-transform:capitalize">${goal.status}</span>
      </div>
      <div class="progress-bar">
        <div class="progress-fill" style="width:${pct}%"></div>
      </div>
      ${subGoalsHTML}
    </div>`;
  }).join('');
}

function showToast(msg, type) {
  const toast = document.createElement('div');
  toast.className = 'toast ' + type;
  toast.textContent = msg;
  document.body.appendChild(toast);
  setTimeout(() => toast.remove(), 4000);
}

function escapeHtml(s) {
  const d = document.createElement('div');
  d.textContent = s;
  return d.innerHTML;
}

// Enter key submits
document.getElementById('goalInput').addEventListener('keydown', (e) => {
  if (e.key === 'Enter') submitGoal();
});

// Connect on load
connectWS();
</script>
</body>
</html>
